// Persistence Of Vision raytracer version 2.0 sample file.

// By Tom Price
// Lots of refraction make this a slow one to trace, but worth it! - dmf

#include "shapes.inc"
#include "colors.inc"
#include "textures.inc"

camera {
   location <0.0, 30.0, -200.0>
   direction <0.0, -0.2, 1.0>
   up <0.0, 1.0, 0.0>
   right <4/3, 0.0, 0.0>
}

plane { y, -60.0
   pigment {
      Pine_Wood
      scale <4.0, 1.0, 2.0>
      rotate 45*y
   }
   finish {
      ambient 0.15
      diffuse 0.8
      brilliance 3.0
      crand 0.01
   }
}

object { Cylinder_X
   pigment { Brown }
   finish {
      crand 0.01
      ambient 0.15
      diffuse 0.8
      reflection 0.4
   }

   scale 5.0
---
/usr/bin/wget
/usr/bin/curl
/usr/bin/tar
/usr/bin/gzip

